def create_metadata_from_http_headers(http_headers: Dict[str, Any]) -> list:
    metadata = []
    
    standard_headers = ['authorization', 'user-agent', 'content-type']
    for header in standard_headers:
        if header in http_headers:
            metadata.append((header, http_headers[header]))
    
